// Bug 1: document.getElementById() butuh string ID, bukan variabel mentah
// Bug 2: updateHitung() didefinisikan di dalam callback, padahal definisi luar sudah ada
// Bug 3: hitung dideklarasikan ulang dengan let di dalam callback

let hitung = 0;

function updateHitung() {
  document.getElementById('hasil').textContent = hitung;
}

document.getElementById('tombol').addEventListener('click', function() {
  let hitung = 0;  // Bug 3: shadowing variabel luar
  const tampilan = document.getElementById(hitung);  // Bug 1: pakai angka, bukan string
  hitung = hitung + 1;

  function updateHitung() {  // Bug 2: mendefinisikan ulang di dalam callback
    tampilan.textContent = hitung;
  }

  updateHitung();
});

solution:
let hitung = 0;

function updateHitung() {
  const tampilan = document.getElementById('hasil');
  tampilan.textContent = hitung;
}

document.getElementById('tombol').addEventListener('click', function() {
  hitung = hitung + 1;
  updateHitung();
  console.log('Tombol berhasil menambah hitungan');
});

verification.testCode:
const code = solution;
assert(code.includes("getElementById('hasil')"), 'Bug #1 belum diperbaiki: getElementById butuh string ID');
assert(code.indexOf('function updateHitung') < code.indexOf('addEventListener'), 'Bug #2 belum diperbaiki: updateHitung harus di luar callback');
assert(code.indexOf('let hitung') === code.lastIndexOf('let hitung'), 'Bug #3 belum diperbaiki: hanya satu deklarasi hitung');
